create table dirkspzm32.pe_eti_drucker_typen (
    lp_type           varchar2(50 char) not null enable,
    gap_height_mm     number(*, 3) default 0 not null enable,
    label_height_mm   number(*, 3) not null enable,
    label_width_mm    number(*, 3) not null enable,
    def_x_offset_mm   number(*, 5) default 0 not null enable,
    def_y_offset_mm   number(*, 5) default 0 not null enable,
    def_font          varchar2(50 char),
    def_font_size     varchar2(50 char),
    dpi               number(*, 5) default 0 not null enable,
    cmd_unit          varchar2(10 char) default 'mm' not null enable,
    lebenszeichen_cmd varchar2(255 char),
    font_xy_pos       varchar2(10 char) default 'TL' not null enable,
    params            varchar2(1000 char)
);

alter table dirkspzm32.pe_eti_drucker_typen
    add constraint pk_pe_eti_drucker_typen primary key ( lp_type )
        using index enable;


